```matlab
function [trapzApprox, numIntegrate] = PlanetDistance(a,b,points)
    trapzApprox = TrapzPlanet(a,b,points);
    numIntegrate = IntegratePlanet(a,b);
end

function trapzApprox = TrapzPlanet(a,b,points)
    % Generate points on the ellipse
    t = linspace(0, 2*pi, points+1);
    x = a*cos(t);
    y = b*sin(t);

    % Calculate the distance between consecutive points
    dx = diff(x);
    dy = diff(y);

    % Calculate the distance traveled using the trapezoidal rule
    distances = sqrt(dx.^2 + dy.^2);
    trapzApprox = trapz(distances);
end

function numIntegrate = IntegratePlanet(a,b)
    % Define a function for the distance traveled on the ellipse
    fun = @(t) sqrt((a*sin(t))^2 + (b*cos(t))^2);

    % Integrate the function over one complete period (0 to 2*pi)
    numIntegrate = integral(fun, 0, 2*pi);
end
```

